import{_ as e,o as t,c as o,ae as s}from"./chunks/framework.Czhw_PXq.js";const w=JSON.parse('{"title":"~/.openclaw vs ~/clawd","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/19_Agent管理专题/06-openclaw-vs-clawd.md","filePath":"chapters/19_Agent管理专题/06-openclaw-vs-clawd.md"}'),n={name:"chapters/19_Agent管理专题/06-openclaw-vs-clawd.md"};function l(c,a,d,p,r,i){return t(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="openclaw-vs-clawd" tabindex="-1">~/.openclaw vs ~/clawd <a class="header-anchor" href="#openclaw-vs-clawd" aria-label="Permalink to &quot;~/.openclaw vs ~/clawd&quot;">​</a></h1><blockquote><p>日期：2026-03-25 来源：内容运营助手群 参考：OpenClaw 官方文档</p></blockquote><hr><p>user: ~/.openclaw vs ~/clawd 全面分析对比关于这个问题,我需要你根据openclaw的官方文档回答</p><p>assistant: 根据官方文档，我找到了以下信息：</p><h2 id="官方定义" tabindex="-1">官方定义 <a class="header-anchor" href="#官方定义" aria-label="Permalink to &quot;官方定义&quot;">​</a></h2><p>根据 OpenClaw 文档：</p><table tabindex="0"><thead><tr><th>目录</th><th>官方定义</th></tr></thead><tbody><tr><td><strong><code>~/.openclaw/</code></strong></td><td><strong>默认状态目录 (State Directory)</strong>，包含配置、凭证，会话数据等</td></tr><tr><td><strong><code>~/.openclaw/workspace/</code></strong></td><td><strong>默认工作空间</strong>，包含 SOUL.md、AGENTS.md、MEMORY.md 等</td></tr></tbody></table><hr><h3 id="官方文档原文" tabindex="-1">官方文档原文 <a class="header-anchor" href="#官方文档原文" aria-label="Permalink to &quot;官方文档原文&quot;">​</a></h3><p>从 <code>/opt/homebrew/lib/node_modules/openclaw/docs/install/migrating.md</code>：</p><blockquote><p>&quot;When you copy the <strong>state directory</strong> (<code>~/.openclaw/</code> by default)...&quot;</p></blockquote><blockquote><p>&quot;Custom profiles use <code>~/.openclaw-&lt;profile&gt;/</code> or a path set via <code>OPENCLAW_STATE_DIR</code>.&quot;</p></blockquote><p>从 <code>/opt/homebrew/lib/node_modules/openclaw/docs/start/openclaw.md</code>：</p><blockquote><p>&quot;By default, OpenClaw uses <code>~/.openclaw/workspace</code> as the agent workspace...&quot;</p></blockquote><hr><h3 id="📊-结构说明" tabindex="-1">📊 结构说明 <a class="header-anchor" href="#📊-结构说明" aria-label="Permalink to &quot;📊 结构说明&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.openclaw/                          ← 状态目录 (State Directory)</span></span>
<span class="line"><span>├── openclaw.json    ← 主配置文件</span></span>
<span class="line"><span>├── credentials/     ← API 凭证</span></span>
<span class="line"><span>├── agents/         ← Agent 会话状态</span></span>
<span class="line"><span>├── workspace/      ← 默认工作空间 (Bootstrap 文件)</span></span>
<span class="line"><span>├── skills/        ← 安装的 Skills</span></span>
<span class="line"><span>├── cron/          ← 定时任务</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><hr><h3 id="⚠️-关于-clawd" tabindex="-1">⚠️ 关于 ~/clawd <a class="header-anchor" href="#⚠️-关于-clawd" aria-label="Permalink to &quot;⚠️ 关于 ~/clawd&quot;">​</a></h3><p><strong>官方文档中没有明确说明 <code>~/clawd</code> 的来源</strong>。</p><p>可能的来源：</p><ol><li><strong>旧版本遗留</strong> - 早期版本使用的目录名</li><li><strong>符号链接</strong> - <code>ls -la ~</code> 显示 <code>~/.clawdbot -&gt; ~/.moltbot</code>，可能是版本演变</li><li><strong>自定义工作区</strong> - 用户手动创建的额外工作空间</li></ol><hr><h3 id="💡-总结" tabindex="-1">💡 总结 <a class="header-anchor" href="#💡-总结" aria-label="Permalink to &quot;💡 总结&quot;">​</a></h3><table tabindex="0"><thead><tr><th>目录</th><th>状态</th><th>官方支持</th></tr></thead><tbody><tr><td><code>~/.openclaw/</code></td><td>✅ 正在使用</td><td>官方默认状态目录</td></tr><tr><td><code>~/clawd/</code></td><td>❓ 不明确</td><td>未在官方文档中找到定义</td></tr></tbody></table><p>建议使用 <strong>~/.openclaw/</strong> 作为主目录，它是 OpenClaw 官方定义的默认路径。</p>`,27)])])}const u=e(n,[["render",l]]);export{w as __pageData,u as default};
